output_schema.structure:

{
  "cluster_id": "string",
  "recommendation": {
    "action_type": "CREATE_SUBCATEGORY | CREATE_TOP_LEVEL | MERGE_CATEGORIES | CREATE_ATTRIBUTE_FILTER | NO_CATEGORY",
    "confidence": "HIGH | MEDIUM | LOW",
    "primary_name": "string | null",
    "alternatives": [
      {
        "name": "string",
        "rank": "number",
        "trade_off": "string"
      }
    ],
    "parent_category": {
      "id": "string | null",
      "name": "string | null"
    },
    "action_details": {
      "merge_sources": ["category_id"] | null,
      "suggested_children": ["string"] | null,
      "implementation_type": "string | null"
    },
    "reasoning": {
      "summary": "string (1-2 sentences)",
      "naming_rationale": "string",
      "placement_rationale": "string",
      "seo_considerations": "string",
      "ux_considerations": "string"
    },
    "seo_metrics": {
      "primary_keyword_volume": "number",
      "total_cluster_volume": "number",
      "estimated_traffic_potential": "number"
    },
    "warnings": ["string"] | null,
    "next_steps": ["string"]
  }
}
